import React, { useState } from "react";

const SocialMediaPractice = () => {
  const [userChoice, setUserChoice] = useState("");
  const [submitted, setSubmitted] = useState(false);
  const [feedback, setFeedback] = useState("");

  const handleSubmit = () => {
    let message = "";
    if (userChoice === "not_safe") {
      message = "✅ Great job! The house number and location tag reveal your address.";
    } else if (userChoice === "safe") {
      message = "❌ Oops! This post shows your house number and location — not safe!";
    } else {
      message = "🤔 Not sure? It's always safer to avoid posting sensitive info.";
    }
    setFeedback(message);
    setSubmitted(true);
  };

  return (
    <div className="min-h-screen w-full bg-gradient-to-br from-blue-100 to-blue-200 flex items-center justify-center px-4 py-10">
      <div className="w-full max-w-xl bg-blue-50 rounded-2xl shadow-lg p-6 space-y-6">
        {/* 标题 */}
        <div className="text-xl font-bold flex items-center space-x-2">
          <span className="text-2xl">📱</span>
          <h1 className="text-gray-800">Social Media Practice</h1>
        </div>

        {/* 🤖 提问 */}
        <div className="flex items-start space-x-3">
          <div className="text-xl">🤖</div>
          <div className="bg-white rounded-xl px-4 py-2 text-sm leading-relaxed shadow">
            Can you spot the privacy risks before posting?<br />
            Let’s find out! Observe this image and choose your answer.
          </div>
        </div>

        {/* 图片缩略图 */}
        <div className="flex justify-center">
          <img
            src="/images/socialmedia/1.jpg"
            alt="social post"
            className="w-64 h-auto object-cover rounded shadow-md hover:scale-105 transition-transform duration-200"
          />
        </div>

        {/* 选项列表 */}
        {!submitted && (
          <>
            <div className="space-y-3 text-sm text-gray-700">
              <label className="flex items-center space-x-2">
                <input type="radio" name="choice" value="safe" onChange={(e) => setUserChoice(e.target.value)} />
                <span>✅ Safe to post</span>
              </label>
              <label className="flex items-center space-x-2">
                <input type="radio" name="choice" value="not_safe" onChange={(e) => setUserChoice(e.target.value)} />
                <span>⚠️ Not safe to post</span>
              </label>
              <label className="flex items-center space-x-2">
                <input type="radio" name="choice" value="not_sure" onChange={(e) => setUserChoice(e.target.value)} />
                <span>🤔 Not sure</span>
              </label>
            </div>
            <button
              onClick={handleSubmit}
              className="w-full mt-4 bg-blue-500 text-white py-2 rounded-lg hover:bg-blue-600 text-sm font-semibold"
            >
              Submit
            </button>
          </>
        )}

        {/* 🤖 提交后反馈 */}
        {submitted && (
          <div className="flex items-start space-x-3 text-sm">
            <div className="text-xl">🤖</div>
            <div className="bg-white rounded-xl px-4 py-2 shadow">
              {feedback}
              <p className="text-gray-600 mt-2">
                🧠 Tip: Don’t share real-time posts with your home number or location.
              </p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SocialMediaPractice;
